const fs = require('fs');
const path = require('path');

const files = [
  '../src/app/DiversionAudio.tsx',
  '../src/app/MoncksOfDoverStreet.tsx',
  '../src/app/SunilGavaskar.tsx'
];

files.forEach(file => {
  const filePath = path.join(__dirname, file);
  let content = fs.readFileSync(filePath, 'utf-8');

  // Replace <img ... > with <img loading="lazy" ... > if it doesn't have it
  content = content.replace(/<img(?!\s+[^>]*loading=)([^>]*)>/g, '<img loading="lazy"$1>');

  // Also try to ensure there's a min-h on images to prevent layout shift if there isn't one.
  // Instead of modifying className complexly, we can do:
  content = content.replace(/(<img[^>]*className=")([^"]*)(")/g, (match, p1, p2, p3) => {
    if (!p2.includes('min-h-')) {
      return `${p1}${p2} min-h-[100px] md:min-h-[200px]${p3}`;
    }
    return match;
  });

  fs.writeFileSync(filePath, content, 'utf-8');
});
console.log('Fixed images!');